    public List<CreditEventReportedEventResponse> getCreditEventReportedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(CREDITEVENTREPORTED_EVENT, transactionReceipt);
        ArrayList<CreditEventReportedEventResponse> responses = new ArrayList<CreditEventReportedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            CreditEventReportedEventResponse typedResponse = new CreditEventReportedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.enterpriseAddress = (String) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.eventType = (BigInteger) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.reporter = (String) eventValues.getIndexedValues().get(2).getValue();
            typedResponse.impact = (BigInteger) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.eventDataHash = (byte[]) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(2).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

