    public static CreditLimitCore deploy(Client client, CryptoKeyPair credential,
            String _initialAdmin) throws ContractException {
        @SuppressWarnings("rawtypes")
        byte[] encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_initialAdmin)));
        CreditLimitCore contract = deploy(CreditLimitCore.class, client, credential, getBinary(client.getCryptoSuite()), getABI(), encodedConstructor, null);
        contract.setTransactionManager(new ProxySignTransactionManager(client));
        return contract;
    }

    public static class CreditEvent extends StaticStruct {
        public String enterpriseAddress;

        public BigInteger eventType;

        public BigInteger impact;

        public byte[] eventDataHash;

        public BigInteger timestamp;

        public CreditEvent(Address enterpriseAddress, Uint8 eventType, Int256 impact,
                Bytes32 eventDataHash, Uint256 timestamp) {
            super(enterpriseAddress,eventType,impact,eventDataHash,timestamp);
            this.enterpriseAddress = enterpriseAddress.getValue();
            this.eventType = eventType.getValue();
            this.impact = impact.getValue();
            this.eventDataHash = eventDataHash.getValue();
            this.timestamp = timestamp.getValue();
        }

        public CreditEvent(String enterpriseAddress, BigInteger eventType, BigInteger impact,
                byte[] eventDataHash, BigInteger timestamp) {
            super(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(enterpriseAddress),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Uint8(eventType),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Int256(impact),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Bytes32(eventDataHash),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Uint256(timestamp));
            this.enterpriseAddress = enterpriseAddress;
            this.eventType = eventType;
            this.impact = impact;
            this.eventDataHash = eventDataHash;
            this.timestamp = timestamp;
        }
    }

